const html = "<!doctype html>\n<html lang=\"es\">\n  <head>\n    <meta charset=\"UTF-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n    <meta name=\"description\" content=\"Sistema web para comercio con ventas, proveedores, stock y facturacion.\" />\n    <link rel=\"icon\" type=\"image/svg+xml\" href=\"/favicon.svg\" />\n    <link rel=\"stylesheet\" href=\"/app.css\" />\n    <title>Comercio 360</title>\n  </head>\n  <body>\n    <div id=\"app\"></div>\n    <script src=\"/app.js\"></script>\n  </body>\n</html>\n";
const css = "@import url('https://fonts.googleapis.com/css2?family=Manrope:wght@400;500;600;700;800&family=Space+Grotesk:wght@500;700&display=swap');\n\n:root {\n  color: #1f2937;\n  background:\n    radial-gradient(circle at top left, rgba(255, 186, 73, 0.24), transparent 24%),\n    radial-gradient(circle at top right, rgba(24, 124, 111, 0.2), transparent 22%),\n    linear-gradient(180deg, #f5efe4 0%, #eef4ef 42%, #f6f8fb 100%);\n  font-family: 'Manrope', sans-serif;\n  font-synthesis: none;\n  text-rendering: optimizeLegibility;\n  -webkit-font-smoothing: antialiased;\n  -moz-osx-font-smoothing: grayscale;\n  --ink: #14213d;\n  --muted: #5f6c7b;\n  --line: rgba(20, 33, 61, 0.1);\n  --panel: rgba(255, 255, 255, 0.74);\n  --accent: #187c6f;\n  --accent-soft: #d9f1ea;\n  --shadow: 0 20px 45px rgba(31, 41, 55, 0.08);\n}\n\n* { box-sizing: border-box; }\nhtml { scroll-behavior: smooth; }\nbody { margin: 0; min-width: 320px; }\nbutton, input, select { font: inherit; }\nbutton { cursor: pointer; }\na { color: inherit; text-decoration: none; }\n#app { min-height: 100vh; }\n.shell { display: grid; grid-template-columns: 280px 1fr; min-height: 100vh; }\n.sidebar {\n  position: sticky; top: 0; display: flex; flex-direction: column; justify-content: space-between;\n  gap: 28px; min-height: 100vh; padding: 28px; background: rgba(20, 33, 61, 0.92); color: #f8fafc;\n}\n.sidebar h1, .content h2, .content h3, .content strong { font-family: 'Space Grotesk', sans-serif; }\n.sidebar h1 { margin: 10px 0 8px; font-size: 2rem; line-height: 1; }\n.eyebrow { margin: 0; text-transform: uppercase; letter-spacing: 0.16em; font-size: 0.72rem; font-weight: 800; opacity: 0.72; }\n.muted, .lead, .table-row p, .top-row p, .sidebar-card span { color: var(--muted); }\n.sidebar .muted, .sidebar-card span { color: rgba(248, 250, 252, 0.72); }\n.menu { display: grid; gap: 10px; }\n.menu a, .sidebar-card { border: 1px solid rgba(255, 255, 255, 0.12); border-radius: 20px; background: rgba(255, 255, 255, 0.06); }\n.menu a { padding: 12px 14px; transition: transform 180ms ease, background 180ms ease; }\n.menu a:hover { transform: translateX(4px); background: rgba(255, 255, 255, 0.14); }\n.sidebar-card { display: grid; gap: 8px; padding: 18px; }\n.sidebar-card strong { font-size: 1.7rem; }\n.label { margin: 0; font-size: 0.86rem; opacity: 0.85; }\n.content { padding: 30px; }\n.hero-panel, .panel, .kpi-card {\n  border: 1px solid var(--line); border-radius: 28px; background: var(--panel);\n  backdrop-filter: blur(16px); box-shadow: var(--shadow);\n}\n.hero-panel {\n  display: flex; justify-content: space-between; gap: 24px; padding: 30px;\n  background: linear-gradient(135deg, rgba(255, 255, 255, 0.94), rgba(228, 248, 242, 0.88)), var(--panel);\n}\n.hero-panel h2 { margin: 8px 0 12px; font-size: clamp(2rem, 4vw, 3.5rem); line-height: 0.98; max-width: 12ch; color: var(--ink); }\n.lead { max-width: 58ch; line-height: 1.6; }\n.hero-stats { display: grid; gap: 14px; min-width: 240px; }\n.hero-stats div { padding: 18px; border-radius: 22px; background: rgba(255, 255, 255, 0.72); border: 1px solid rgba(20, 33, 61, 0.08); }\n.hero-stats span, .kpi-card span, .panel-head span { display: block; font-size: 0.9rem; color: var(--muted); }\n.hero-stats strong, .kpi-card strong { display: block; margin-top: 10px; color: var(--ink); font-size: 1.7rem; }\n.kpis, .grid-two, .workspace { display: grid; gap: 18px; margin-top: 18px; }\n.kpis { grid-template-columns: repeat(4, minmax(0, 1fr)); }\n.grid-two, .workspace { grid-template-columns: repeat(2, minmax(0, 1fr)); }\n.kpi-card { padding: 22px; }\n.kpi-card p { margin-bottom: 0; color: var(--muted); }\n.kpi-card.accent { background: linear-gradient(145deg, #187c6f, #125e54); color: #f8fafc; }\n.kpi-card.accent span, .kpi-card.accent p, .kpi-card.accent strong { color: inherit; }\n.panel { padding: 22px; }\n.panel-head { display: flex; justify-content: space-between; gap: 16px; align-items: start; margin-bottom: 18px; }\n.panel-head h3 { margin: 0; color: var(--ink); font-size: 1.2rem; }\n.top-list, .alerts, .table-list { display: grid; gap: 12px; }\n.top-row, .alert, .table-row {\n  display: flex; justify-content: space-between; gap: 16px; align-items: center; padding: 14px 16px;\n  border-radius: 18px; background: rgba(255, 255, 255, 0.75); border: 1px solid rgba(20, 33, 61, 0.06);\n}\n.rank {\n  display: grid; place-items: center; width: 44px; height: 44px; border-radius: 14px;\n  background: var(--accent-soft); color: var(--accent); font-weight: 800;\n}\n.alert { align-items: start; flex-direction: column; }\n.alert.warning { border-color: rgba(245, 158, 11, 0.24); background: rgba(255, 247, 214, 0.92); }\n.alert.success { border-color: rgba(24, 124, 111, 0.2); background: rgba(223, 247, 239, 0.92); }\n.alert.info { border-color: rgba(59, 130, 246, 0.2); background: rgba(226, 238, 255, 0.92); }\n.form-grid { display: grid; grid-template-columns: repeat(2, minmax(0, 1fr)); gap: 14px; }\n.form-grid label { display: grid; gap: 8px; color: var(--ink); font-weight: 600; }\n.form-grid input, .form-grid select {\n  width: 100%; padding: 12px 14px; border: 1px solid rgba(20, 33, 61, 0.12);\n  border-radius: 14px; background: #ffffff; color: var(--ink);\n}\n.form-grid .checkbox { grid-column: span 2; display: flex; align-items: center; gap: 10px; }\n.form-grid .checkbox input { width: auto; }\n.form-grid button {\n  grid-column: span 2; padding: 14px 18px; border: none; border-radius: 16px;\n  background: var(--ink); color: #ffffff; font-weight: 800;\n}\n.empty, .table-row p, .top-row p, .alert p, .kpi-card p { margin-top: 4px; }\n.table-row strong, .top-row strong, .alert strong { color: var(--ink); }\n\n@media (max-width: 1120px) {\n  .shell { grid-template-columns: 1fr; }\n  .sidebar { position: relative; min-height: auto; }\n  .kpis { grid-template-columns: repeat(2, minmax(0, 1fr)); }\n}\n\n@media (max-width: 760px) {\n  .content, .sidebar { padding: 20px; }\n  .hero-panel, .panel-head, .table-row, .top-row { flex-direction: column; align-items: start; }\n  .hero-panel, .kpis, .grid-two, .workspace, .form-grid { grid-template-columns: 1fr; }\n  .form-grid .checkbox, .form-grid button { grid-column: span 1; }\n}\n";
const js = "const currency = new Intl.NumberFormat('es-AR', {\n  style: 'currency',\n  currency: 'ARS',\n  maximumFractionDigits: 0,\n})\n\nconst today = new Date().toISOString().slice(0, 10)\n\nconst seedData = {\n  business: {\n    name: 'Mercado Central Demo',\n    owner: 'Lucia Torres',\n    shift: 'Turno tarde',\n  },\n  products: [\n    { id: crypto.randomUUID(), name: 'Yerba Tradicional 1kg', sku: 'YT-100', stock: 22, price: 5400, minStock: 10, category: 'Almacen' },\n    { id: crypto.randomUUID(), name: 'Galletitas de Avena', sku: 'GA-014', stock: 14, price: 1850, minStock: 8, category: 'Kiosco' },\n    { id: crypto.randomUUID(), name: 'Lavandina 2L', sku: 'LV-210', stock: 7, price: 3200, minStock: 9, category: 'Limpieza' },\n    { id: crypto.randomUUID(), name: 'Aceite de Girasol 900ml', sku: 'AG-900', stock: 18, price: 4100, minStock: 6, category: 'Almacen' },\n  ],\n  providers: [\n    { id: crypto.randomUUID(), name: 'Distribuidora Norte', contact: 'Marina Lopez', phone: '11 4321 9988', balance: 128000, lastDelivery: '2026-07-09', category: 'Almacen' },\n    { id: crypto.randomUUID(), name: 'Higiene Sur', contact: 'Jorge Benitez', phone: '11 5511 4010', balance: 42000, lastDelivery: '2026-07-11', category: 'Limpieza' },\n  ],\n  sales: [\n    { id: crypto.randomUUID(), item: 'Yerba Tradicional 1kg', quantity: 3, amount: 16200, channel: 'Mostrador', paid: true, date: '2026-07-12' },\n    { id: crypto.randomUUID(), item: 'Aceite de Girasol 900ml', quantity: 2, amount: 8200, channel: 'WhatsApp', paid: true, date: '2026-07-12' },\n    { id: crypto.randomUUID(), item: 'Lavandina 2L', quantity: 1, amount: 3200, channel: 'Delivery', paid: false, date: '2026-07-11' },\n  ],\n  invoices: [\n    { id: crypto.randomUUID(), number: 'A-0003-000184', client: 'Punto Verde', total: 48600, status: 'Emitida', dueDate: '2026-07-20', type: 'A' },\n    { id: crypto.randomUUID(), number: 'B-0001-000992', client: 'Consumidor Final', total: 8200, status: 'Cobrada', dueDate: '2026-07-12', type: 'B' },\n  ],\n}\n\nconst storageKey = 'comercio360-data'\n\nconst loadState = () => {\n  const saved = localStorage.getItem(storageKey)\n  if (!saved) return structuredClone(seedData)\n\n  try {\n    return { ...structuredClone(seedData), ...JSON.parse(saved) }\n  } catch {\n    return structuredClone(seedData)\n  }\n}\n\nlet state = loadState()\n\nconst saveState = () => {\n  localStorage.setItem(storageKey, JSON.stringify(state))\n}\n\nconst money = (value) => currency.format(Number(value) || 0)\n\nconst getMetrics = () => {\n  const totalSales = state.sales.reduce((sum, sale) => sum + sale.amount, 0)\n  const unpaidSales = state.sales.filter((sale) => !sale.paid).reduce((sum, sale) => sum + sale.amount, 0)\n  const payables = state.providers.reduce((sum, provider) => sum + provider.balance, 0)\n  const pendingInvoices = state.invoices.filter((invoice) => invoice.status !== 'Cobrada').reduce((sum, invoice) => sum + invoice.total, 0)\n  const lowStock = state.products.filter((product) => product.stock <= product.minStock)\n\n  return { totalSales, unpaidSales, payables, pendingInvoices, lowStock }\n}\n\nconst getTopProducts = () => {\n  const sold = new Map()\n\n  for (const sale of state.sales) {\n    sold.set(sale.item, (sold.get(sale.item) || 0) + sale.quantity)\n  }\n\n  return [...sold.entries()].sort((a, b) => b[1] - a[1]).slice(0, 4)\n}\n\nconst app = document.querySelector('#app')\n\nconst render = () => {\n  const metrics = getMetrics()\n  const topProducts = getTopProducts()\n\n  app.innerHTML = `\n    <div class=\"shell\">\n      <aside class=\"sidebar\">\n        <div>\n          <p class=\"eyebrow\">Comercio 360</p>\n          <h1>${state.business.name}</h1>\n          <p class=\"muted\">${state.business.owner} · ${state.business.shift}</p>\n        </div>\n        <nav class=\"menu\">\n          <a href=\"#resumen\">Resumen</a>\n          <a href=\"#ventas\">Ventas</a>\n          <a href=\"#inventario\">Inventario</a>\n          <a href=\"#proveedores\">Proveedores</a>\n          <a href=\"#facturacion\">Facturacion</a>\n        </nav>\n        <div class=\"sidebar-card\">\n          <p class=\"label\">Caja del dia</p>\n          <strong>${money(metrics.totalSales - metrics.unpaidSales)}</strong>\n          <span>${state.sales.filter((sale) => sale.date === today).length} movimientos registrados hoy</span>\n        </div>\n      </aside>\n\n      <main class=\"content\">\n        <section class=\"hero-panel\" id=\"resumen\">\n          <div>\n            <p class=\"eyebrow\">Operacion diaria</p>\n            <h2>Controla ventas, compras y facturas desde un solo tablero.</h2>\n            <p class=\"lead\">La app guarda informacion en este navegador para que el equipo pueda trabajar con una base simple, rapida y sin configuraciones extra.</p>\n          </div>\n          <div class=\"hero-stats\">\n            <div>\n              <span>Ventas acumuladas</span>\n              <strong>${money(metrics.totalSales)}</strong>\n            </div>\n            <div>\n              <span>Cuentas a pagar</span>\n              <strong>${money(metrics.payables)}</strong>\n            </div>\n          </div>\n        </section>\n\n        <section class=\"kpis\">\n          <article class=\"kpi-card accent\">\n            <span>Facturacion pendiente</span>\n            <strong>${money(metrics.pendingInvoices)}</strong>\n            <p>${state.invoices.filter((invoice) => invoice.status !== 'Cobrada').length} comprobantes por seguir</p>\n          </article>\n          <article class=\"kpi-card\">\n            <span>Ventas sin cobrar</span>\n            <strong>${money(metrics.unpaidSales)}</strong>\n            <p>${state.sales.filter((sale) => !sale.paid).length} operaciones abiertas</p>\n          </article>\n          <article class=\"kpi-card\">\n            <span>Alertas de stock</span>\n            <strong>${metrics.lowStock.length}</strong>\n            <p>${metrics.lowStock[0] ? metrics.lowStock[0].name : 'Sin alertas criticas'}</p>\n          </article>\n          <article class=\"kpi-card\">\n            <span>Proveedores activos</span>\n            <strong>${state.providers.length}</strong>\n            <p>Ultimo ingreso ${state.providers[0]?.lastDelivery ?? '-'}</p>\n          </article>\n        </section>\n\n        <section class=\"grid-two\">\n          <article class=\"panel\">\n            <div class=\"panel-head\">\n              <h3>Productos mas vendidos</h3>\n              <span>Ranking rapido</span>\n            </div>\n            <div class=\"top-list\">\n              ${topProducts.length\n                ? topProducts\n                    .map(\n                      ([item, quantity], index) => `\n                        <div class=\"top-row\">\n                          <span class=\"rank\">0${index + 1}</span>\n                          <div>\n                            <strong>${item}</strong>\n                            <p>${quantity} unidades vendidas</p>\n                          </div>\n                        </div>`,\n                    )\n                    .join('')\n                : '<p class=\"empty\">Todavia no hay ventas cargadas.</p>'}\n            </div>\n          </article>\n\n          <article class=\"panel\">\n            <div class=\"panel-head\">\n              <h3>Alertas operativas</h3>\n              <span>Lo que conviene resolver hoy</span>\n            </div>\n            <div class=\"alerts\">\n              ${\n                metrics.lowStock.length\n                  ? metrics.lowStock\n                      .map(\n                        (product) => `\n                          <div class=\"alert warning\">\n                            <strong>${product.name}</strong>\n                            <p>Stock ${product.stock} / minimo ${product.minStock}</p>\n                          </div>`,\n                      )\n                      .join('')\n                  : '<div class=\"alert success\"><strong>Inventario estable</strong><p>No hay productos debajo del minimo.</p></div>'\n              }\n              ${\n                state.invoices.some((invoice) => invoice.status === 'Emitida')\n                  ? '<div class=\"alert info\"><strong>Seguimiento comercial</strong><p>Hay facturas emitidas que todavia no figuran como cobradas.</p></div>'\n                  : ''\n              }\n            </div>\n          </article>\n        </section>\n\n        <section class=\"workspace\" id=\"ventas\">\n          <article class=\"panel\">\n            <div class=\"panel-head\">\n              <h3>Cargar venta</h3>\n              <span>Descuenta stock y actualiza caja</span>\n            </div>\n            <form class=\"form-grid\" data-form=\"sale\">\n              <label>\n                Producto\n                <select name=\"item\" required>\n                  ${state.products.map((product) => `<option value=\"${product.name}\">${product.name}</option>`).join('')}\n                </select>\n              </label>\n              <label>\n                Cantidad\n                <input type=\"number\" name=\"quantity\" min=\"1\" value=\"1\" required />\n              </label>\n              <label>\n                Monto total\n                <input type=\"number\" name=\"amount\" min=\"1\" placeholder=\"5400\" required />\n              </label>\n              <label>\n                Canal\n                <select name=\"channel\">\n                  <option>Mostrador</option>\n                  <option>WhatsApp</option>\n                  <option>Delivery</option>\n                  <option>Mayorista</option>\n                </select>\n              </label>\n              <label class=\"checkbox\">\n                <input type=\"checkbox\" name=\"paid\" checked />\n                Cobrado\n              </label>\n              <button type=\"submit\">Registrar venta</button>\n            </form>\n          </article>\n\n          <article class=\"panel\">\n            <div class=\"panel-head\">\n              <h3>Ultimas ventas</h3>\n              <span>Historial reciente</span>\n            </div>\n            <div class=\"table-list\">\n              ${state.sales\n                .slice()\n                .reverse()\n                .slice(0, 6)\n                .map(\n                  (sale) => `\n                    <div class=\"table-row\">\n                      <div>\n                        <strong>${sale.item}</strong>\n                        <p>${sale.date} · ${sale.channel}</p>\n                      </div>\n                      <div>\n                        <strong>${money(sale.amount)}</strong>\n                        <p>${sale.quantity} un. · ${sale.paid ? 'Cobrado' : 'Pendiente'}</p>\n                      </div>\n                    </div>`,\n                )\n                .join('')}\n            </div>\n          </article>\n        </section>\n\n        <section class=\"workspace\" id=\"inventario\">\n          <article class=\"panel\">\n            <div class=\"panel-head\">\n              <h3>Agregar producto</h3>\n              <span>Control de stock minimo</span>\n            </div>\n            <form class=\"form-grid\" data-form=\"product\">\n              <label>\n                Nombre\n                <input type=\"text\" name=\"name\" placeholder=\"Cafe molido 500g\" required />\n              </label>\n              <label>\n                SKU\n                <input type=\"text\" name=\"sku\" placeholder=\"CF-500\" required />\n              </label>\n              <label>\n                Stock inicial\n                <input type=\"number\" name=\"stock\" min=\"0\" required />\n              </label>\n              <label>\n                Precio\n                <input type=\"number\" name=\"price\" min=\"0\" required />\n              </label>\n              <label>\n                Stock minimo\n                <input type=\"number\" name=\"minStock\" min=\"0\" required />\n              </label>\n              <label>\n                Categoria\n                <input type=\"text\" name=\"category\" placeholder=\"Almacen\" required />\n              </label>\n              <button type=\"submit\">Guardar producto</button>\n            </form>\n          </article>\n\n          <article class=\"panel\">\n            <div class=\"panel-head\">\n              <h3>Inventario actual</h3>\n              <span>${state.products.length} productos</span>\n            </div>\n            <div class=\"table-list\">\n              ${state.products\n                .map(\n                  (product) => `\n                    <div class=\"table-row\">\n                      <div>\n                        <strong>${product.name}</strong>\n                        <p>${product.sku} · ${product.category}</p>\n                      </div>\n                      <div>\n                        <strong>${product.stock} un.</strong>\n                        <p>${money(product.price)} · minimo ${product.minStock}</p>\n                      </div>\n                    </div>`,\n                )\n                .join('')}\n            </div>\n          </article>\n        </section>\n\n        <section class=\"workspace\" id=\"proveedores\">\n          <article class=\"panel\">\n            <div class=\"panel-head\">\n              <h3>Nuevo proveedor</h3>\n              <span>Compras y cuentas a pagar</span>\n            </div>\n            <form class=\"form-grid\" data-form=\"provider\">\n              <label>\n                Empresa\n                <input type=\"text\" name=\"name\" required />\n              </label>\n              <label>\n                Contacto\n                <input type=\"text\" name=\"contact\" required />\n              </label>\n              <label>\n                Telefono\n                <input type=\"text\" name=\"phone\" required />\n              </label>\n              <label>\n                Saldo pendiente\n                <input type=\"number\" name=\"balance\" min=\"0\" required />\n              </label>\n              <label>\n                Ultima entrega\n                <input type=\"date\" name=\"lastDelivery\" value=\"${today}\" required />\n              </label>\n              <label>\n                Categoria\n                <input type=\"text\" name=\"category\" required />\n              </label>\n              <button type=\"submit\">Guardar proveedor</button>\n            </form>\n          </article>\n\n          <article class=\"panel\">\n            <div class=\"panel-head\">\n              <h3>Proveedores</h3>\n              <span>Seguimiento de compras</span>\n            </div>\n            <div class=\"table-list\">\n              ${state.providers\n                .map(\n                  (provider) => `\n                    <div class=\"table-row\">\n                      <div>\n                        <strong>${provider.name}</strong>\n                        <p>${provider.contact} · ${provider.phone}</p>\n                      </div>\n                      <div>\n                        <strong>${money(provider.balance)}</strong>\n                        <p>${provider.category} · ultima entrega ${provider.lastDelivery}</p>\n                      </div>\n                    </div>`,\n                )\n                .join('')}\n            </div>\n          </article>\n        </section>\n\n        <section class=\"workspace\" id=\"facturacion\">\n          <article class=\"panel\">\n            <div class=\"panel-head\">\n              <h3>Emitir factura</h3>\n              <span>Comprobantes basicos</span>\n            </div>\n            <form class=\"form-grid\" data-form=\"invoice\">\n              <label>\n                Numero\n                <input type=\"text\" name=\"number\" placeholder=\"B-0001-001245\" required />\n              </label>\n              <label>\n                Cliente\n                <input type=\"text\" name=\"client\" required />\n              </label>\n              <label>\n                Total\n                <input type=\"number\" name=\"total\" min=\"1\" required />\n              </label>\n              <label>\n                Tipo\n                <select name=\"type\">\n                  <option>A</option>\n                  <option>B</option>\n                  <option>C</option>\n                </select>\n              </label>\n              <label>\n                Vencimiento\n                <input type=\"date\" name=\"dueDate\" value=\"${today}\" required />\n              </label>\n              <label>\n                Estado\n                <select name=\"status\">\n                  <option>Emitida</option>\n                  <option>En revision</option>\n                  <option>Cobrada</option>\n                </select>\n              </label>\n              <button type=\"submit\">Guardar factura</button>\n            </form>\n          </article>\n\n          <article class=\"panel\">\n            <div class=\"panel-head\">\n              <h3>Facturas recientes</h3>\n              <span>Control de cobro</span>\n            </div>\n            <div class=\"table-list\">\n              ${state.invoices\n                .slice()\n                .reverse()\n                .map(\n                  (invoice) => `\n                    <div class=\"table-row\">\n                      <div>\n                        <strong>${invoice.number}</strong>\n                        <p>${invoice.client} · tipo ${invoice.type}</p>\n                      </div>\n                      <div>\n                        <strong>${money(invoice.total)}</strong>\n                        <p>${invoice.status} · vence ${invoice.dueDate}</p>\n                      </div>\n                    </div>`,\n                )\n                .join('')}\n            </div>\n          </article>\n        </section>\n      </main>\n    </div>\n  `\n\n  bindEvents()\n}\n\nconst bindEvents = () => {\n  for (const form of document.querySelectorAll('form[data-form]')) {\n    form.addEventListener('submit', handleSubmit)\n  }\n}\n\nconst handleSubmit = (event) => {\n  event.preventDefault()\n\n  const form = event.currentTarget\n  const formData = new FormData(form)\n  const kind = form.dataset.form\n\n  if (kind === 'sale') {\n    const item = formData.get('item')\n    const quantity = Number(formData.get('quantity'))\n    const amount = Number(formData.get('amount'))\n    const paid = formData.get('paid') === 'on'\n    const product = state.products.find((entry) => entry.name === item)\n\n    if (product) {\n      product.stock = Math.max(0, product.stock - quantity)\n    }\n\n    state.sales.push({\n      id: crypto.randomUUID(),\n      item,\n      quantity,\n      amount,\n      channel: formData.get('channel'),\n      paid,\n      date: today,\n    })\n  }\n\n  if (kind === 'product') {\n    state.products.push({\n      id: crypto.randomUUID(),\n      name: formData.get('name'),\n      sku: formData.get('sku'),\n      stock: Number(formData.get('stock')),\n      price: Number(formData.get('price')),\n      minStock: Number(formData.get('minStock')),\n      category: formData.get('category'),\n    })\n  }\n\n  if (kind === 'provider') {\n    state.providers.unshift({\n      id: crypto.randomUUID(),\n      name: formData.get('name'),\n      contact: formData.get('contact'),\n      phone: formData.get('phone'),\n      balance: Number(formData.get('balance')),\n      lastDelivery: formData.get('lastDelivery'),\n      category: formData.get('category'),\n    })\n  }\n\n  if (kind === 'invoice') {\n    state.invoices.push({\n      id: crypto.randomUUID(),\n      number: formData.get('number'),\n      client: formData.get('client'),\n      total: Number(formData.get('total')),\n      type: formData.get('type'),\n      dueDate: formData.get('dueDate'),\n      status: formData.get('status'),\n    })\n  }\n\n  saveState()\n  form.reset()\n  render()\n}\n\nrender()\n";
